/* =======================================
   OPEN TAQIBAT
======================================= */

function openTaqibat(id){

const item = taqibat.find(t => t.id === id);

if(!item){
return;
}

openPage("taqibatReadingPage");

document.getElementById("readingTitle").textContent =
item.urdu;

document.getElementById("readingEnglishTitle").textContent =
item.english;

document.getElementById("readingArabic").innerHTML =
item.arabic;

document.getElementById("readingUrdu").innerHTML =
item.translation;

document.getElementById("readingReference").innerHTML =
item.reference;
const bismillahBox =
document.querySelector("#taqibatReadingPage .readingBismillah");

if(item.bismillah){
bismillahBox.textContent = "بِسْمِ اللّٰهِ الرَّحْمٰنِ الرَّحِيمِ";
if(item.bismillah){
    bismillahBox.style.display = "block";
}else{
    bismillahBox.style.display = "none";
}
}
}